const raw = $input.first().json;
const allBiz = Array.isArray(raw) ? raw : (Array.isArray(raw.body) ? raw.body : [raw]);

if (allBiz.length === 0) {
  return [{ json: { skip: true, reason: 'No active businesses' } }];
}

const seen = new Set();
const businesses = allBiz.filter(biz => {
  if (!biz.telegram_chat_id) return false;
  if (seen.has(biz.telegram_chat_id)) return false;
  seen.add(biz.telegram_chat_id);
  return true;
});

if (businesses.length === 0) {
  return [{ json: { skip: true, reason: 'No businesses with Telegram' } }];
}

const now = new Date();
const todayStr      = now.toISOString().split('T')[0];
const tomorrow      = new Date(now); tomorrow.setDate(now.getDate() + 1);
const tomorrowStr   = tomorrow.toISOString().split('T')[0];
const yesterday     = new Date(now); yesterday.setDate(now.getDate() - 1);
const yesterdayStr  = yesterday.toISOString().split('T')[0];
const dow           = now.getDay() || 7;
const mon           = new Date(now); mon.setDate(now.getDate() - dow + 1);
const weekStartStr  = mon.toISOString().split('T')[0];
const lastWeekMon   = new Date(mon); lastWeekMon.setDate(mon.getDate() - 7);
const lastWeekStr   = lastWeekMon.toISOString().split('T')[0];
const monthStartStr = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];

return businesses.map(biz => ({
  json: {
    business_id:        biz.business_id,
    business_name:      biz.business_name,
    telegram_chat_id:   biz.telegram_chat_id,
    website_url:        biz.website_url,
    wc_consumer_key:    biz.wc_consumer_key_encrypted,
    wc_consumer_secret: biz.wc_consumer_secret_encrypted,
    reportDate:         todayStr,
    todayStart:         todayStr + 'T00:00:00',
    todayEnd:           tomorrowStr + 'T00:00:00',
    yesterdayStart:     yesterdayStr + 'T00:00:00',
    yesterdayEnd:       todayStr + 'T00:00:00',
    weekStart:          weekStartStr + 'T00:00:00',
    weekEnd:            tomorrowStr + 'T00:00:00',
    lastWeekStart:      lastWeekStr + 'T00:00:00',
    lastWeekEnd:        weekStartStr + 'T00:00:00',
    monthStart:         monthStartStr + 'T00:00:00',
    monthEnd:           tomorrowStr + 'T00:00:00'
  }
}));

const d = $input.first().json;

return [{
  json: {
    ...d,
    syncUrl: `${d.website_url}/wp-json/wc/v3/orders?status=completed,processing&per_page=100&orderby=date&order=desc&after=${d.yesterdayStart}`,
    syncReady: true
  }
}];

const d   = $('Prepare WC Sync').first().json;
const raw = $input.first().json;
const orders = Array.isArray(raw.body) ? raw.body : [];
const business_id = d.business_id;

if (orders.length === 0) {
  return [{ json: { ...d, _synced_orders: 0, _order_batch: [], _line_items_batch: [] } }];
}

const orderBatch = orders.map(o => ({
  business_id,
  wc_order_id:           o.id,
  order_number:          String(o.number || o.id),
  status:                o.status || 'pending',
  currency:              o.currency || 'PKR',
  total:                 parseFloat(o.total) || 0,
  total_refunded:        parseFloat(o.total_refunded) || 0,
  subtotal:              parseFloat(o.subtotal) || 0,
  tax_total:             parseFloat(o.total_tax) || 0,
  shipping_total:        parseFloat(o.shipping_total) || 0,
  discount_total:        parseFloat(o.discount_total) || 0,
  customer_email:        o.billing?.email || null,
  customer_phone:        o.billing?.phone || null,
  customer_name:         o.billing ? `${o.billing.first_name||''} ${o.billing.last_name||''}`.trim() || null : null,
  billing_address:       o.billing || {},
  shipping_address:      o.shipping || {},
  line_items:            o.line_items || [],
  payment_method:        o.payment_method || null,
  payment_method_title:  o.payment_method_title || null,
  transaction_id:        o.transaction_id || null,
  date_created:          o.date_created || null,
  date_modified:         o.date_modified || null,
  date_completed:        o.date_completed || null,
  date_paid:             o.date_paid || null,
  last_synced_at:        new Date().toISOString()
}));

const lineItemsBatch = [];
for (const o of orders) {
  for (const item of (o.line_items || [])) {
    if (!item.id) continue;
    lineItemsBatch.push({
      business_id,
      wc_order_id:      o.id,
      wc_order_item_id: item.id,
      product_id:       item.product_id || null,
      variation_id:     item.variation_id || null,
      product_name:     (item.name || 'Unknown').substring(0, 500),
      sku:              item.sku || null,
      quantity:         parseInt(item.quantity) || 1,
      price:            parseFloat(item.price) || 0,
      subtotal:         parseFloat(item.subtotal) || 0,
      total:            parseFloat(item.total) || 0,
      tax:              parseFloat(item.total_tax) || 0,
      order_date:       o.date_created || null,
      order_status:     o.status || null,
      last_synced_at:   new Date().toISOString()
    });
  }
}

return [{ json: { ...d, _synced_orders: orders.length, _order_batch: orderBatch, _line_items_batch: lineItemsBatch } }];

const biz = $('Prepare WC Sync').first().json;

function calcSales(nodeName) {
  try {
    const raw = $(nodeName).first().json;
    const rows = raw.body ? raw.body : (Array.isArray(raw) ? raw : []);
    const totalOrders  = rows.length;
    const netSales     = rows.reduce((s, r) => s + (parseFloat(r.total)||0) - (parseFloat(r.total_refunded)||0), 0);
    const grossRevenue = rows.reduce((s, r) => s + (parseFloat(r.total)||0), 0);
    const currency     = rows[0]?.currency || 'PKR';
    return { totalOrders, netSales, grossRevenue, currency };
  } catch(e) {
    return { totalOrders: 0, netSales: 0, grossRevenue: 0, currency: 'PKR' };
  }
}

function getTopProducts(nodeName) {
  try {
    const allItems = $(nodeName).all();
    let rows = [];
    if (allItems.length > 1) {
      rows = allItems.map(item => item.json);
    } else {
      const raw = allItems[0]?.json || {};
      rows = Array.isArray(raw) ? raw : (raw.body ? raw.body : []);
    }
    const productMap = {};
    rows.forEach(r => {
      const name = r.product_name || 'Unknown';
      if (!productMap[name]) productMap[name] = { qty: 0, revenue: 0 };
      productMap[name].qty     += parseInt(r.quantity) || 0;
      productMap[name].revenue += parseFloat(r.total) || 0;
    });
    return Object.entries(productMap).sort((a, b) => b[1].revenue - a[1].revenue).slice(0, 3);
  } catch(e) { return []; }
}

// Only run on last trigger (when Query Top Products Last Week feeds us)
const inputNode = $input.first().json;
const inputHasProducts = inputNode.product_name !== undefined;
// If input is from Top Products Week (not Last Week), skip — wait for Last Week
// We check by seeing if lastWeekStart exists in biz — always true so just build report

const today        = calcSales('Query Today Sales');
const yesterday    = calcSales('Query Yesterday Sales');
const week         = calcSales('Query This Week Sales');
const topProducts  = getTopProducts('Query Top Products Week');
const lastWeekProd = getTopProducts('Query Top Products Last Week');

const fmt = n => n.toLocaleString('en', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const currency = today.currency || yesterday.currency || 'PKR';

let growthStr = '';
if (yesterday.netSales > 0) {
  const growth = ((today.netSales - yesterday.netSales) / yesterday.netSales * 100).toFixed(1);
  growthStr = parseFloat(growth) >= 0 ? ` 📈 +${growth}%` : ` 📉 ${growth}%`;
}

let msg = `📊 *Daily Sales Report*\n`;
msg += `📅 ${biz.reportDate} | 🏢 ${biz.business_name}\n`;
msg += `━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

msg += `*Today*\n`;
if (today.totalOrders > 0) {
  msg += `✅ Orders: ${today.totalOrders}${growthStr}\n`;
  msg += `💰 Net Sales: ${currency} ${fmt(today.netSales)}\n`;
  msg += `📦 Gross: ${currency} ${fmt(today.grossRevenue)}\n`;
} else {
  msg += `No orders today.\n`;
}

msg += `\n*Yesterday*\n`;
if (yesterday.totalOrders > 0) {
  msg += `✅ Orders: ${yesterday.totalOrders}\n`;
  msg += `💰 Net Sales: ${currency} ${fmt(yesterday.netSales)}\n`;
} else {
  msg += `No orders yesterday.\n`;
}

msg += `\n*This Week*\n`;
if (week.totalOrders > 0) {
  msg += `✅ Orders: ${week.totalOrders}\n`;
  msg += `💰 Net Sales: ${currency} ${fmt(week.netSales)}\n`;
  msg += `📦 Gross: ${currency} ${fmt(week.grossRevenue)}\n`;
} else {
  msg += `No orders this week yet.\n`;
}

if (topProducts.length > 0) {
  msg += `\n*🏆 Top Products (This Week)*\n`;
  topProducts.forEach(([name, d], idx) => {
    msg += `${idx+1}. ${name} — ${d.qty} units | ${currency} ${fmt(d.revenue)}\n`;
  });
}

if (lastWeekProd.length > 0) {
  msg += `\n*📦 Top Products (Last Week)*\n`;
  lastWeekProd.forEach(([name, d], idx) => {
    msg += `${idx+1}. ${name} — ${d.qty} units | ${currency} ${fmt(d.revenue)}\n`;
  });
}

msg += `\n_Automated report by BizFlow AI_`;

if (msg.length > 4000) msg = msg.substring(0, 4000) + '...\n_BizFlow AI_';

return [{ json: { ...biz, reportMessage: msg } }];
